request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?midType ?midVal ?gatewayType ?gateway ?gwName ?gwId WHERE {
  ?model a bboExt:Model .

  { 
    ?model tai:normalizedId ?midVal .
    BIND("normalizedId" AS ?midType)
  }
  UNION
  {
    ?model tai:originalId ?midVal .
    BIND("originalId" AS ?midType)
  }

  FILTER(?midVal = "5ee15f85aeb74d8d9e31df0e41fea6fe")

  ?gateway a ?gatewayType .
  FILTER(?gatewayType IN (bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:EventBasedGateway))
  ?gateway tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .

  OPTIONAL { ?gateway bbo:name ?gwName . }
  OPTIONAL { ?gateway bbo:id ?gwId . }
}
LIMIT 25
